args.cypher:
// Find the HierarchicalStructures submodel of Hall3 and traverse its entity tree
MATCH (aas:AssetAdministrationShell {idShort: 'Hall3'})-[:HAS_SUBMODEL]->(sm:Submodel)
      -[:HAS_SEMANTIC_ID]->(:SemanticConcept {id: 'https://admin-shell.io/idta/HierarchicalStructures/1/1/Submodel'})

// Traverse the entity tree: EntryNode -> Node (Hall) -> Node (device)
MATCH (sm)-[:HAS_ELEMENT*]->(hallNode:Entity)-[:HAS_ELEMENT]->(hasPartRel:RelationshipElement)
WHERE hasPartRel.idShort = 'HasPart'

// Follow the HasPart relationship to find what's in the hall
MATCH (hasPartRel)-[:HAS_SECOND]->(ref)
RETURN hallNode.idShort AS hallNode, ref.idShort AS secondId, ref.value AS secondValue, labels(ref) AS refLabels

// List all submodels and their elements for UR20_001
MATCH (aas:AssetAdministrationShell {idShort: "UR20_001"})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort AS submodel, sm.id AS smId

// Get all elements in the FacilityInformation submodel of Hall 3
MATCH (sm:Submodel {id: "urn:submodel:hall3:facilityinformation"})-[:HAS_ELEMENT]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.value

// Get Hall 3 Facility Information
MATCH (sm:Submodel {id: "urn:submodel:hall3:facilityinformation"})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value

// Find the actual semanticId used by the hall HierarchicalStructures submodel
MATCH (sm:Submodel {idShort: 'HierarchicalStructures'})-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN sm.id, sc.id, sm.idShort

// List all submodels on the first AGV with their contents
MATCH (aas:AssetAdministrationShell {id: $aasId})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN sm.idShort, sm.id

// List all submodels on all three AGVs
MATCH (aas:AssetAdministrationShell {id: $aasId})-[:HAS_SUBMODEL]->(sm:Submodel)
RETURN aas.idShort, aas.id, sm.idShort, sm.id

// Get technical data properties from the MiR100 type AGV
MATCH (sm:Submodel {idShort: $smIdShort})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType

// List all submodel IDs and their semanticIds that exist in the graph
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN DISTINCT sc.id ORDER BY sc.id

// Get technical data from instance shells for AGVs
// First, find the technical data submodel on each instance
MATCH (instance:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
WHERE instance.idShort IN ['MiR100_001', 'MiR250_001', 'MiR250_002']
OPTIONAL MATCH (sm)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN instance.idShort AS robot, sm.idShort, sm.id, sc.id AS templateSemanticId

// Check the graphSemanticIds for hierarchical structures - note the note says it stripped the suffix
// Let's try without the /Submodel suffix
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
WHERE sc.id CONTAINS 'HierarchicalStructures'
RETURN sm.idShort, sc.id

// Find all AAS and their assets to identify the transport robot in Hall 4
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetType

// List all elements inside the HierarchicalStructures submodel
MATCH (sm:Submodel {id: 'urn:submodel:hall4:hierarchicalstructures'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.smId

// Check the SRN submodel that exists on the MiR100_001 instance
MATCH (sm:Submodel {id: "urn:aas-hybrid-mcp:srn:001:0112b117"})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort, p.value, p.valueType
